import React, { useState } from 'react';
import api from '../../api/axios'; // Importing the Axios instance we created
import { Plus, Trash2, Save } from 'lucide-react'; // Icons for better UI

const InterviewerAvailability = () => {
    const [slots, setSlots] = useState(['']); // Array of ISO date strings
    const [price, setPrice] = useState(0);
    const [loading, setLoading] = useState(false);

    // Add a new empty slot input
    const addSlot = () => setSlots([...slots, '']);

    // Remove a specific slot
    const removeSlot = (index) => {
        const newSlots = slots.filter((_, i) => i !== index);
        setSlots(newSlots);
    };

    // Update the value of a specific slot
    const handleSlotChange = (index, value) => {
        const newSlots = [...slots];
        newSlots[index] = value;
        setSlots(newSlots);
    };

    const handleSave = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            // This calls your PUT /api/v1/interviewer/availability endpoint
            await api.put('/v1/interviewer/availability', { 
                slots: slots.filter(s => s !== ''), // Remove empty strings
                price: parseFloat(price) 
            });
            alert("Availability and Pricing updated successfully!");
        } catch (err) {
            alert("Error updating availability: " + err.response?.data?.message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="max-w-2xl mx-auto mt-10 p-6 bg-white rounded-xl shadow-md">
            <h1 className="text-2xl font-bold text-gray-800 mb-6">Manage Your Availability</h1>

            <form onSubmit={handleSave} className="space-y-6">
                {/* Pricing Section */}
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Price Per Session ($)</label>
                    <input 
                        type="number" 
                        value={price}
                        onChange={(e) => setPrice(e.target.value)}
                        className="w-full p-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                        required
                    />
                </div>

                {/* Slots Section */}
                <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Available Time Slots</label>
                    {slots.map((slot, index) => (
                        <div key={index} className="flex gap-2 mb-3">
                            <input 
                                type="datetime-local" 
                                value={slot}
                                onChange={(e) => handleSlotChange(index, e.target.value)}
                                className="flex-1 p-2 border border-gray-300 rounded-md"
                                required
                            />
                            <button 
                                type="button"
                                onClick={() => removeSlot(index)}
                                className="p-2 text-red-500 hover:bg-red-50 rounded-md"
                            >
                                <Trash2 size={20} />
                            </button>
                        </div>
                    ))}
                    <button 
                        type="button"
                        onClick={addSlot}
                        className="flex items-center gap-2 text-blue-600 hover:text-blue-700 font-medium mt-2"
                    >
                        <Plus size={18} /> Add Another Slot
                    </button>
                </div>

                <button 
                    type="submit"
                    disabled={loading}
                    className="w-full bg-blue-600 text-white py-2 px-4 rounded-md hover:bg-blue-700 flex items-center justify-center gap-2 transition-colors"
                >
                    <Save size={20} /> {loading ? 'Saving...' : 'Save All Changes'}
                </button>
            </form>
        </div>
    );
};

export default InterviewerAvailability;
